"use client";

/**
 * UserMenu Component
 *
 * A dropdown profile menu for SaaS applications.
 * Optimized for Product Mode with efficient user account management.
 *
 * @example
 * ```tsx
 * <UserMenu
 *   user={{ name: 'John Doe', email: 'john@example.com' }}
 *   sections={[
 *     { id: 'account', items: [{ id: 'profile', label: 'Profile' }] }
 *   ]}
 * />
 * ```
 */

import { forwardRef, useState, useRef, useEffect } from "react";
import { ChevronDown } from "lucide-react";
import type { UserMenuProps, UserMenuItem } from "./UserMenu.types";
import styles from "./UserMenu.module.css";

// Status indicator colors
const statusColors: Record<string, string> = {
  online: "var(--text-success)",
  away: "var(--text-warning)",
  busy: "var(--text-error)",
  offline: "var(--text-tertiary)",
};

export const UserMenu = forwardRef<HTMLDivElement, UserMenuProps>(
  (
    {
      user,
      sections,
      open: controlledOpen,
      onOpenChange,
      trigger,
      align = "end",
      placement = "bottom",
      showHeader = true,
      compact = false,
      fullWidth = false,
      className,
      ...rest
    },
    ref,
  ) => {
    const [internalOpen, setInternalOpen] = useState(false);
    const menuRef = useRef<HTMLDivElement>(null);
    const triggerRef = useRef<HTMLButtonElement>(null);

    const isOpen = controlledOpen !== undefined ? controlledOpen : internalOpen;

    const setOpen = (value: boolean) => {
      if (controlledOpen === undefined) {
        setInternalOpen(value);
      }
      onOpenChange?.(value);
    };

    // Close on outside click
    useEffect(() => {
      const handleClickOutside = (event: MouseEvent) => {
        if (
          menuRef.current &&
          !menuRef.current.contains(event.target as Node) &&
          triggerRef.current &&
          !triggerRef.current.contains(event.target as Node)
        ) {
          setOpen(false);
        }
      };

      if (isOpen) {
        document.addEventListener("mousedown", handleClickOutside);
        return () =>
          document.removeEventListener("mousedown", handleClickOutside);
      }
    }, [isOpen]);

    // Close on escape
    useEffect(() => {
      const handleEscape = (event: KeyboardEvent) => {
        if (event.key === "Escape" && isOpen) {
          setOpen(false);
          triggerRef.current?.focus();
        }
      };

      document.addEventListener("keydown", handleEscape);
      return () => document.removeEventListener("keydown", handleEscape);
    }, [isOpen]);

    const handleItemClick = (item: UserMenuItem) => {
      if (item.disabled) return;
      item.onClick?.();
      setOpen(false);
    };

    const getInitials = (name: string) => {
      return name
        .split(" ")
        .map((n) => n[0])
        .join("")
        .toUpperCase()
        .slice(0, 2);
    };

    const classNames = [
      styles.userMenu,
      fullWidth && styles.userMenuFullWidth,
      className,
    ]
      .filter(Boolean)
      .join(" ");
    const triggerClasses = [styles.trigger, compact && styles.triggerCompact]
      .filter(Boolean)
      .join(" ");
    const dropdownClasses = [
      styles.dropdown,
      isOpen && styles.dropdownOpen,
      align === "start" && styles.dropdownStart,
      placement === "top" && styles.dropdownTop,
    ]
      .filter(Boolean)
      .join(" ");

    return (
      <div ref={ref} className={classNames} {...rest}>
        {/* Trigger */}
        {trigger ? (
          <div onClick={() => setOpen(!isOpen)}>{trigger}</div>
        ) : (
          <button
            ref={triggerRef}
            type="button"
            className={triggerClasses}
            onClick={() => setOpen(!isOpen)}
            aria-expanded={isOpen}
            aria-haspopup="true"
          >
            <div className={styles.avatar}>
              {user.avatar ? (
                <img
                  src={user.avatar}
                  alt={user.name}
                  className={styles.avatarImage}
                />
              ) : (
                <span className={styles.avatarInitials}>
                  {user.initials || getInitials(user.name)}
                </span>
              )}
              {user.status && (
                <span
                  className={styles.statusIndicator}
                  style={{ backgroundColor: statusColors[user.status] }}
                />
              )}
            </div>
            {!compact && (
              <>
                <div className={styles.triggerInfo}>
                  <span className={styles.triggerName}>{user.name}</span>
                  {user.role && (
                    <span className={styles.triggerRole}>{user.role}</span>
                  )}
                </div>
                <ChevronDown
                  size={16}
                  className={`${styles.chevron} ${isOpen ? styles.chevronOpen : ""}`}
                />
              </>
            )}
          </button>
        )}

        {/* Dropdown */}
        <div ref={menuRef} className={dropdownClasses} role="menu">
          {showHeader && (
            <div className={styles.header}>
              <div className={styles.headerAvatar}>
                {user.avatar ? (
                  <img
                    src={user.avatar}
                    alt={user.name}
                    className={styles.avatarImage}
                  />
                ) : (
                  <span className={styles.avatarInitials}>
                    {user.initials || getInitials(user.name)}
                  </span>
                )}
              </div>
              <div className={styles.headerInfo}>
                <span className={styles.headerName}>{user.name}</span>
                {user.email && (
                  <span className={styles.headerEmail}>{user.email}</span>
                )}
              </div>
            </div>
          )}

          {sections.map((section, sectionIndex) => (
            <div key={section.id} className={styles.section}>
              {section.label && (
                <div className={styles.sectionLabel}>{section.label}</div>
              )}
              {section.items.map((item) => {
                const itemClasses = [
                  styles.item,
                  item.danger && styles.itemDanger,
                  item.disabled && styles.itemDisabled,
                ]
                  .filter(Boolean)
                  .join(" ");

                if (item.href && !item.disabled) {
                  return (
                    <a
                      key={item.id}
                      href={item.href}
                      className={itemClasses}
                      role="menuitem"
                      onClick={() => setOpen(false)}
                    >
                      {item.icon && (
                        <span className={styles.itemIcon}>{item.icon}</span>
                      )}
                      <span>{item.label}</span>
                      {item.badge !== undefined && (
                        <span className={styles.itemBadge}>{item.badge}</span>
                      )}
                      {item.shortcut && (
                        <span className={styles.itemShortcut}>
                          {item.shortcut}
                        </span>
                      )}
                    </a>
                  );
                }

                return (
                  <button
                    key={item.id}
                    type="button"
                    className={itemClasses}
                    role="menuitem"
                    disabled={item.disabled}
                    onClick={() => handleItemClick(item)}
                  >
                    {item.icon && (
                      <span className={styles.itemIcon}>{item.icon}</span>
                    )}
                    <span>{item.label}</span>
                    {item.badge !== undefined && (
                      <span className={styles.itemBadge}>{item.badge}</span>
                    )}
                    {item.shortcut && (
                      <span className={styles.itemShortcut}>
                        {item.shortcut}
                      </span>
                    )}
                  </button>
                );
              })}
              {sectionIndex < sections.length - 1 && (
                <div className={styles.divider} />
              )}
            </div>
          ))}
        </div>
      </div>
    );
  },
);

UserMenu.displayName = "UserMenu";

/**
 * UserMenu Component Types
 *
 * Type definitions for the Orion UserMenu section component.
 * A dropdown profile menu for SaaS applications.
 */

import type { HTMLAttributes, ReactNode } from "react";

/**
 * User menu item
 */
export interface UserMenuItem {
  /**
   * Unique identifier
   */
  id: string;

  /**
   * Item label
   */
  label: string;

  /**
   * Optional icon
   */
  icon?: ReactNode;

  /**
   * Link URL
   */
  href?: string;

  /**
   * Click handler
   */
  onClick?: () => void;

  /**
   * Danger styling (for logout, delete account, etc.)
   */
  danger?: boolean;

  /**
   * Disabled state
   */
  disabled?: boolean;

  /**
   * Keyboard shortcut hint (e.g., "⌘K", "Ctrl+S")
   */
  shortcut?: string;

  /**
   * Notification badge count
   */
  badge?: number;
}

/**
 * User menu section (group of items)
 */
export interface UserMenuSection {
  /**
   * Section ID
   */
  id: string;

  /**
   * Optional section label
   */
  label?: string;

  /**
   * Items in this section
   */
  items: UserMenuItem[];
}

/**
 * User info displayed in menu header
 */
export interface UserInfo {
  /**
   * User's display name
   */
  name: string;

  /**
   * User's email
   */
  email?: string;

  /**
   * Avatar URL
   */
  avatar?: string;

  /**
   * Initials fallback (if no avatar)
   */
  initials?: string;

  /**
   * Status indicator
   */
  status?: "online" | "away" | "busy" | "offline";

  /**
   * Role or subscription tier
   */
  role?: string;
}

/**
 * UserMenu section props
 *
 * @example
 * ```tsx
 * <UserMenu
 *   user={{ name: 'John Doe', email: 'john@example.com', avatar: '/avatar.jpg' }}
 *   sections={[
 *     { id: 'account', items: [{ id: 'profile', label: 'Profile', icon: <User /> }] },
 *     { id: 'actions', items: [{ id: 'logout', label: 'Sign out', danger: true }] }
 *   ]}
 * />
 * ```
 */
export interface UserMenuProps extends Omit<
  HTMLAttributes<HTMLDivElement>,
  "children"
> {
  /**
   * User information
   */
  user: UserInfo;

  /**
   * Menu sections
   */
  sections: UserMenuSection[];

  /**
   * Open state (controlled)
   */
  open?: boolean;

  /**
   * Open state change handler
   */
  onOpenChange?: (open: boolean) => void;

  /**
   * Trigger element (custom trigger button)
   */
  trigger?: ReactNode;

  /**
   * Menu alignment
   * @default "end"
   */
  align?: "start" | "end";

  /**
   * Dropdown placement direction
   * @default "bottom"
   */
  placement?: "top" | "bottom";

  /**
   * Show user info header in dropdown
   * @default true
   */
  showHeader?: boolean;

  /**
   * Compact mode (smaller trigger)
   * @default false
   */
  compact?: boolean;

  /**
   * Whether the menu wrapper should stretch to fill its container
   * Set to true when UserMenu is inside a constrained container (e.g., sidebar footer)
   * Changes wrapper from display: inline-block to display: block with width: 100%
   * @default false
   */
  fullWidth?: boolean;
}

/**
 * UserMenu Component Styles
 *
 * Optimized for Product Mode (SaaS dashboards).
 * Clean dropdown menu with efficient user account management.
 */

.userMenu {
  position: relative;
  display: inline-block;
}

/* Full-width modifier */
.userMenuFullWidth {
  display: block;
  width: 100%;
}

.userMenuFullWidth .trigger {
  width: 100%;
  min-width: 0;
}

/* ============================================================================
 * TRIGGER
 * ============================================================================ */

.trigger {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
  padding: var(--spacing-2) var(--spacing-3);
  background: transparent;
  border: none;
  border-radius: var(--radius-control);
  cursor: pointer;
  transition: background-color var(--mode-hover-duration);
}

.trigger:hover {
  background: var(--surface-subtle);
}

.triggerCompact {
  padding: var(--spacing-1);
}

.avatar {
  position: relative;
  width: 32px;
  height: 32px;
  border-radius: var(--radius-full);
  overflow: hidden;
  background: var(--interactive-primary);
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.avatarImage {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.avatarInitials {
  font-family: var(--font-secondary);
  font-size: var(--font-size-12);
  font-weight: var(--font-weight-semibold);
  color: var(--interactive-primary-text);
  text-transform: uppercase;
}

.statusIndicator {
  position: absolute;
  bottom: 0;
  right: 0;
  width: 10px;
  height: 10px;
  border-radius: var(--radius-full);
  border: 2px solid var(--surface-base);
}

.triggerInfo {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  gap: var(--spacing-0-5);
  flex: 1;
  min-width: 0;
  overflow: hidden;
}

.triggerName {
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  font-weight: var(--font-weight-medium);
  color: var(--text-primary);
  line-height: 1.2;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.triggerRole {
  font-family: var(--font-secondary);
  font-size: var(--font-size-11);
  color: var(--text-tertiary);
  line-height: 1.2;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.chevron {
  color: var(--text-tertiary);
  transition: transform var(--mode-hover-duration);
  flex-shrink: 0;
  margin-left: auto;
}

.chevronOpen {
  transform: rotate(180deg);
}

/* ============================================================================
 * DROPDOWN
 * ============================================================================ */

.dropdown {
  position: absolute;
  top: calc(100% + var(--spacing-1));
  right: 0;
  z-index: var(--z-modal);
  min-width: 220px;
  background: var(--surface-base);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius-control);
  box-shadow: var(--shadow-lg);
  opacity: 0;
  visibility: hidden;
  transform: translateY(-8px);
  transition: all var(--mode-hover-duration);
}

.dropdownOpen {
  opacity: 1;
  visibility: visible;
  transform: translateY(0);
}

.dropdownStart {
  right: auto;
  left: 0;
}

/* ============================================================================
 * HEADER
 * ============================================================================ */

.header {
  display: flex;
  align-items: center;
  gap: var(--spacing-3);
  padding: var(--spacing-3) var(--spacing-4);
  border-bottom: 1px solid var(--border-subtle);
}

.headerAvatar {
  width: 40px;
  height: 40px;
  border-radius: var(--radius-full);
  overflow: hidden;
  background: var(--interactive-primary);
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.headerAvatar .avatarInitials {
  font-size: var(--font-size-14);
}

.headerInfo {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-0-5);
  min-width: 0;
}

.headerName {
  font-family: var(--font-secondary);
  font-size: var(--font-size-14);
  font-weight: var(--font-weight-semibold);
  color: var(--text-primary);
  line-height: 1.2;
}

.headerEmail {
  font-family: var(--font-secondary);
  font-size: var(--font-size-12);
  color: var(--text-tertiary);
  line-height: 1.2;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* ============================================================================
 * SECTIONS
 * ============================================================================ */

.section {
  padding: var(--spacing-2) 0;
}

.sectionLabel {
  font-family: var(--font-secondary);
  font-size: var(--font-size-11);
  font-weight: var(--font-weight-semibold);
  color: var(--text-tertiary);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  padding: var(--spacing-1) var(--spacing-4) var(--spacing-2);
}

.divider {
  height: 1px;
  background: var(--border-subtle);
  margin: var(--spacing-2) 0;
}

/* ============================================================================
 * ITEMS
 * ============================================================================ */

.item {
  display: flex;
  align-items: center;
  gap: var(--spacing-3);
  width: 100%;
  padding: var(--spacing-2) var(--spacing-4);
  background: none;
  border: none;
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  color: var(--text-primary);
  text-decoration: none;
  text-align: left;
  cursor: pointer;
  transition: background-color var(--mode-hover-duration);
}

.item:hover {
  background: var(--surface-subtle);
}

.itemIcon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 20px;
  color: var(--text-secondary);
}

.itemDanger {
  color: var(--text-error);
}

.itemDanger .itemIcon {
  color: var(--text-error);
}

.itemDisabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.itemDisabled:hover {
  background: none;
}

/* ============================================================================
 * DROPDOWN PLACEMENT & ITEM DETAILS
 * ============================================================================ */

/* Opens upward */
.dropdownTop {
  top: auto;
  bottom: calc(100% + var(--spacing-1));
  transform: translateY(8px);
}

.dropdownTop.dropdownOpen {
  transform: translateY(0);
}

/* Keyboard shortcut hint on item */
.itemShortcut {
  margin-left: auto;
  font-size: var(--font-size-12);
  color: var(--text-tertiary);
  font-family: var(--font-mono);
  flex-shrink: 0;
}

/* Notification badge on item */
.itemBadge {
  margin-left: auto;
  min-width: 18px;
  height: 18px;
  border-radius: var(--radius-full);
  background: var(--interactive-primary);
  color: var(--interactive-primary-text);
  font-size: var(--font-size-11);
  font-family: var(--font-secondary);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0 var(--spacing-1);
  flex-shrink: 0;
}

/* ============================================================================
 * RESPONSIVE
 * ============================================================================ */

@media (max-width: 480px) {
  .dropdown {
    position: fixed;
    top: auto;
    bottom: 0;
    left: 0;
    right: 0;
    min-width: 100%;
    border-radius: var(--radius-container) var(--radius-container) 0 0;
    transform: translateY(100%);
  }

  .dropdownOpen {
    transform: translateY(0);
  }
}

export { UserMenu } from "./UserMenu";
export type {
  UserMenuProps,
  UserMenuItem,
  UserMenuSection,
  UserInfo,
} from "./UserMenu.types";
